import React, { useState, useEffect } from 'react';
import api from '../services/api';

const estadoConfig = {
  borrador:     { label: 'Borrador',     bg: '#f1f5f9', color: '#64748b', dot: '#94a3b8' },
  pendiente:    { label: 'Pendiente',    bg: '#fffbeb', color: '#b45309', dot: '#f59e0b' },
  rechazada:    { label: 'Rechazada',    bg: '#fef2f2', color: '#b91c1c', dot: '#ef4444' },
  aprobada:     { label: 'Aprobada',     bg: '#f0fdf4', color: '#15803d', dot: '#22c55e' },
  ficha_creada: { label: 'Ficha creada', bg: '#eff6ff', color: '#1d4ed8', dot: '#3b82f6' },
  con_inscritos:{ label: 'Con inscritos',bg: '#faf5ff', color: '#6d28d9', dot: '#8b5cf6' },
  completada:   { label: 'Completada',   bg: '#f8fafc', color: '#0f172a', dot: '#334155' },
};

const formatFecha = (fecha) => {
  if (!fecha) return '—';
  return new Date(fecha).toLocaleDateString('es-CO', { day: '2-digit', month: 'short', year: 'numeric' });
};

const MisOfertas = () => {
  const [ofertas, setOfertas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');
  const [filtroEstado, setFiltroEstado] = useState('todos');
  const [hoveredRow, setHoveredRow] = useState(null);

  useEffect(() => { cargarOfertas(); }, []);

  const cargarOfertas = async () => {
    try {
      setLoading(true);
      const response = await api.get('/ofertas/mis-ofertas');
      setOfertas(response.data.data || []);
    } catch (err) {
      setError('Error al cargar las ofertas');
    } finally {
      setLoading(false);
    }
  };

  const verDetalle = (ofertaId) => {
    alert(`Ver detalle de oferta ${ofertaId} - Próximamente`);
  };

  const estadosPresentes = [...new Set(ofertas.map(o => o.estado?.codigo).filter(Boolean))];

  const filtradas = ofertas.filter((o) => {
    const q = search.toLowerCase();
    const matchSearch =
      o.programa_formacion?.nombre_programa?.toLowerCase().includes(q) ||
      o.programa_formacion?.codigo?.toLowerCase().includes(q);
    const matchEstado = filtroEstado === 'todos' || o.estado?.codigo === filtroEstado;
    return matchSearch && matchEstado;
  });

  const getCuposColor = (disp, max) => {
    if (!max) return '#94a3b8';
    const r = disp / max;
    return r > 0.5 ? '#10b981' : r > 0.2 ? '#f59e0b' : '#ef4444';
  };

  if (loading) {
    return (
      <>
        <style>{globalStyles}</style>
        <div style={styles.loadingWrapper}>
          <div style={styles.spinner} />
          <p style={styles.loadingText}>Cargando ofertas...</p>
        </div>
      </>
    );
  }

  return (
    <>
      <style>{globalStyles}</style>
      <div style={styles.page}>

        {/* Header */}
        <div style={styles.header}>
          <div style={styles.headerLeft}>
            <div style={styles.headerIcon}><ListIcon /></div>
            <div>
              <h1 style={styles.title}>Mis Ofertas</h1>
              <p style={styles.subtitle}>Seguimiento de tus programas de formación</p>
            </div>
          </div>
          {ofertas.length > 0 && (
            <div style={styles.countBadge}>
              <span style={styles.countNumber}>{ofertas.length}</span>
              <span style={styles.countLabel}>ofertas</span>
            </div>
          )}
        </div>

        {/* Error */}
        {error && (
          <div style={styles.errorAlert}>
            <AlertIcon />
            <span>{error}</span>
          </div>
        )}

        {/* Empty */}
        {!error && ofertas.length === 0 ? (
          <div style={styles.emptyState}>
            <div style={styles.emptyIcon}><InboxIcon /></div>
            <h3 style={styles.emptyTitle}>Sin ofertas creadas</h3>
            <p style={styles.emptyText}>Ve a "Crear Oferta" para comenzar a gestionar tus programas.</p>
          </div>
        ) : (
          <>
            {/* Toolbar */}
            <div style={styles.toolbar}>
              <div style={styles.searchWrapper}>
                <span style={styles.searchIcon}><SearchIcon /></span>
                <input
                  type="text"
                  placeholder="Buscar por programa o código..."
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  style={styles.searchInput}
                />
                {search && (
                  <button onClick={() => setSearch('')} style={styles.clearBtn}><CloseIcon /></button>
                )}
              </div>

              {/* Estado filters */}
              <div style={styles.filters}>
                <button
                  onClick={() => setFiltroEstado('todos')}
                  style={{ ...styles.filterBtn, ...(filtroEstado === 'todos' ? styles.filterBtnActive : {}) }}
                  className="btn-hover"
                >
                  Todos
                </button>
                {estadosPresentes.map((cod) => {
                  const cfg = estadoConfig[cod] || { label: cod, dot: '#94a3b8' };
                  const isActive = filtroEstado === cod;
                  return (
                    <button
                      key={cod}
                      onClick={() => setFiltroEstado(cod)}
                      style={{
                        ...styles.filterBtn,
                        ...(isActive ? { ...styles.filterBtnActive, background: cfg.bg, color: cfg.color, borderColor: cfg.dot } : {}),
                      }}
                      className="btn-hover"
                    >
                      <span style={{ ...styles.dot, background: cfg.dot }} />
                      {cfg.label}
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Result info */}
            {(search || filtroEstado !== 'todos') && (
              <p style={styles.resultInfo}>
                {filtradas.length} resultado{filtradas.length !== 1 ? 's' : ''}
                {filtroEstado !== 'todos' && ` · ${estadoConfig[filtroEstado]?.label || filtroEstado}`}
                {search && ` · "${search}"`}
              </p>
            )}

            {/* Table */}
            <div style={styles.tableWrapper}>
              <table style={styles.table}>
                <thead>
                  <tr>
                    {['Programa', 'Código', 'Tipo', 'Inicio', 'Fin', 'Cupos', 'Estado', ''].map((h) => (
                      <th key={h} style={styles.th}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {filtradas.map((oferta) => {
                    const cfg = estadoConfig[oferta.estado?.codigo] || estadoConfig.borrador;
                    const cuposColor = getCuposColor(oferta.cupos_disponibles, oferta.cupo_maximo);
                    const isHovered = hoveredRow === oferta._id;

                    return (
                      <tr
                        key={oferta._id}
                        style={{ ...styles.tr, ...(isHovered ? styles.trHovered : {}) }}
                        onMouseEnter={() => setHoveredRow(oferta._id)}
                        onMouseLeave={() => setHoveredRow(null)}
                      >
                        <td style={{ ...styles.td, ...styles.tdPrograma }}>
                          {oferta.programa_formacion?.nombre_programa || '—'}
                        </td>
                        <td style={styles.td}>
                          <span style={styles.codigoPill}>
                            {oferta.programa_formacion?.codigo || '—'}
                          </span>
                        </td>
                        <td style={styles.td}>
                          <span style={{
                            ...styles.tipoPill,
                            ...(oferta.es_campesena
                              ? { background: '#fef9c3', color: '#854d0e', border: '1px solid #fde68a' }
                              : { background: '#f1f5f9', color: '#475569', border: '1px solid #e2e8f0' })
                          }}>
                            {oferta.es_campesena ? 'Campesena' : 'Regular'}
                          </span>
                        </td>
                        <td style={{ ...styles.td, ...styles.tdFecha }}>{formatFecha(oferta.fechas?.inicio)}</td>
                        <td style={{ ...styles.td, ...styles.tdFecha }}>{formatFecha(oferta.fechas?.fin)}</td>
                        <td style={styles.td}>
                          <span style={{ ...styles.cuposText, color: cuposColor }}>
                            {oferta.cupos_disponibles ?? 0}
                            <span style={styles.cuposMax}>/{oferta.cupo_maximo ?? 0}</span>
                          </span>
                        </td>
                        <td style={styles.td}>
                          <span style={{
                            ...styles.estadoBadge,
                            background: cfg.bg,
                            color: cfg.color,
                          }}>
                            <span style={{ ...styles.dot, background: cfg.dot }} />
                            {cfg.label}
                          </span>
                        </td>
                        <td style={{ ...styles.td, textAlign: 'right' }}>
                          <button
                            onClick={() => verDetalle(oferta._id)}
                            style={styles.detailBtn}
                            className="btn-hover"
                          >
                            <EyeIcon />
                            Detalle
                          </button>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>

              {filtradas.length === 0 && (
                <div style={styles.noResults}>
                  Sin resultados para los filtros actuales.
                </div>
              )}
            </div>
          </>
        )}
      </div>
    </>
  );
};

/* ── Icons ── */
const ListIcon = () => (
  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
